SELECT /* base.sy :: SyhBatchLog :: selectList */ l.* , ste.site_nm AS site_nm FROM syh_batch_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id
ORDER BY l.batch_log_id ASC ORDER BY l.batch_log_id DESC ORDER BY l.batch_nm ASC ORDER BY l.batch_nm DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.sy :: SyhBatchLog :: selectPageList */ l.* , ste.site_nm AS site_nm FROM syh_batch_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id
ORDER BY l.batch_log_id ASC ORDER BY l.batch_log_id DESC ORDER BY l.batch_nm ASC ORDER BY l.batch_nm DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{limit} OFFSET #{offset}
